import React, { useState } from 'react';

function SearchComponent({ entityName, entityIdKey, onSearch, onEdit, onDelete }) {
  const [searchId, setSearchId] = useState('');
  const [searchResult, setSearchResult] = useState(null);
  const [searchError, setSearchError] = useState(null);

  const handleSearchClick = async () => {
    if (!searchId) {
      setSearchError(`Please enter a ${entityName} ID.`);
      setSearchResult(null);
      return;
    }
    setSearchError(null);
    try {
      const record = await onSearch(searchId);
      setSearchResult(record);
      setSearchError(null);
    } catch (err) {
      setSearchResult(null);
      setSearchError(err.message || 'Record not found.');
    }
  };

  return (
    <div style={{ border: '1px solid #ccc', padding: '15px', margin: '20px 0', background: '#f9f9f9' }}>
      <h3>Search {entityName} by ID</h3>
      <input
        type="number"
        value={searchId}
        onChange={(e) => setSearchId(e.target.value)}
        placeholder={`Enter ${entityName} ID`}
        style={{ padding: '8px', marginRight: '10px' }}
      />
      <button onClick={handleSearchClick} style={{ padding: '8px 15px' }}>Search</button>

      {searchError && <p style={{ color: 'red', marginTop: '10px' }}>{searchError}</p>}

      {searchResult && (
        <div style={{ marginTop: '15px', borderTop: '1px dashed #ccc', paddingTop: '10px' }}>
          <h4>Search Result: {entityName} ID {searchResult[entityIdKey]}</h4>
          <div style={{ background: '#f8f9fa', padding: '15px', border: '1px solid #dee2e6', borderRadius: '5px' }}>
            {Object.entries(searchResult).map(([key, value]) => {
              // Skip the ID field since it's already shown in the header
              if (key === entityIdKey) return null;
              
              // Format the field name for display
              const displayKey = key.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase());
              
              // Handle null values
              const displayValue = value === null || value === undefined ? 'N/A' : value;
              
              return (
                <div key={key} style={{ marginBottom: '8px', display: 'flex', justifyContent: 'space-between' }}>
                  <strong>{displayKey}:</strong>
                  <span>{displayValue}</span>
                </div>
              );
            })}
          </div>
          <div style={{ marginTop: '15px' }}>
            <button onClick={() => onEdit(searchResult)} style={{ padding: '8px 15px', marginRight: '10px' }}>
              Edit This Record
            </button>
            <button 
                onClick={() => onDelete(searchResult[entityIdKey])} 
                style={{ padding: '8px 15px', color: 'red', border: '1px solid red', background: 'white' }}
            >
                Delete This Record
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

export default SearchComponent;
